var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"용건을 꺼내기 전에, 우선 한 잔 하실래요?","JPN":"用件を話す前に、まずは一杯どうですか？","ENG":" Before we talk business, how about a drink first?","TWN":"在談正事之前，先喝一杯怎麼樣？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"네? 수녀가 술을 권해도 되냐고요?","JPN":"えっ？　シスターがお酒を勧めてもいいのかって？","ENG":" Huh? You think it's strange for a nun to offer a drink?","TWN":"嗯？修女怎麼可以叫人喝酒嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"풋, 가게에서 계속 절 찾으시던 분이 할 말은 아니지 않나요?","JPN":"ぷふっ、お店でずっと私を探していた方が言うようなことじゃないですね。","ENG":" Pfft, coming from someone who was constantly looking for me at the bar, isn't that a bit funny?","TWN":"噗，是誰一天到晚來店裡找我的？你說這種話不覺得奇怪嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아마도- 술에 취해서 사고만 안 치면 괜찮을 걸요?","JPN":"たぶん、酔っぱらって問題を起こさない限りは大丈夫ですよ。","ENG":" Probably... just as long as you don't get drunk and cause trouble, it should be fine.","TWN":"反正，只要喝醉後不鬧事的話，應該沒問題吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"게다가 아시잖아요? 저 쉽게 안 취해요.","JPN":"それに、わかってるでしょう？　私、そう簡単には酔いません。","ENG":" Besides, you know this already. I don't get drunk that easily.","TWN":"而且你也知道，我可不是那麼容易醉的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"취하지 않아도 술은 사람을 솔직하게 만들어주니까요. 중요한 얘길 나누는 자리에선 이 한 잔이 도움이 될 것 같네요.","JPN":"酔わなくてもお酒は人を素直にしてくれますから。重要な話をする時には、この一杯が役に立ちそうですね。","ENG":"Even if I don't get drunk, alcohol makes people honest. In a conversation like this, a drink might help.","TWN":"不需要到喝醉的程度，酒也能使人變得坦率。在這種重要的談話場合，喝一杯應該會有幫助吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"네? 당신이 칵테일을 만든다고요? 이 순간을 위해서 연습까지…?","JPN":"えっ？　カクテルを作ってくれるんですか？　この瞬間のために練習まで……？","ENG":" Huh? You're making me a cocktail? Wait... you actually practiced for this?","TWN":"嗯？你要幫我調一杯雞尾酒？是特地為我練習的…？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"손놀림이 제법이시네요.","JPN":"なかなかの手さばきですね。","ENG":"Not bad. You've got some skills.","TWN":"你的技巧很熟練呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"으핫- 냄새-","JPN":"うわっ、ちょ、あなた！","ENG":" Whoa... what is that smell?","TWN":"呃呃—這味道—"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"뭘 넣은 거죠? 이 독한 향은?!","JPN":"何を入れたんですか？　この強い香りは！？","ENG":"What did you put in this?! It reeks!","TWN":"你在裡面放什麼？這股濃烈的味道是什麼？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"사고칠까봐 걱정되면 안 마셔도 된다니… 그 얄팍한 도발은 뭔가요?","JPN":"問題を起こすことが心配なら飲まなくてもいいって……その浅はかな挑発は何ですか？","ENG":"Telling me I don't have to drink if I'm worried about causing trouble... Hah, is that really the best provocation you've got?","TWN":"說什麼如果怕闖禍的話可以不喝……這種拙劣的激將法是怎麼回事？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그래도 기껏 만들었는데 거절하면 실례겠죠?","JPN":"でも、せっかく作ってくれたのに断るのも失礼ですよね。","ENG":" After all that effort, it'd be rude not to drink it, right?","TWN":"不過，既然是你特地做的，我要是拒絕的話，豈不是太失禮？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"후아-","JPN":"ふわぁー","ENG":" Huah!","TWN":"呼～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"이거, 좋은데요? 레시피가 궁금해요!","JPN":"これ、いいですね。レシピが気になります！","ENG":" This, is actually good! Tell me the recipe!","TWN":"這杯酒，還不錯呢！好奇你的調酒配方！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"응? 진짜 다 마실 줄은 몰랐다는 그 반응은 뭐죠?","JPN":"うん？　何ですか？　本当に全部飲み干すとは、みたいな反応は。","ENG":" Huh? What's with that look? Don't tell me you didn't actually expect me to finish it.","TWN":"嗯？怎樣？你不會真的沒想到我會全部喝光吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그건 계약서...? 설마 처음부터 그럴 목적으로 독한 칵테일을 준 건가요?","JPN":"契約書にサインを？　最初からこれが目的だったんですか？","ENG":" You want me to sign the contract? So that was your goal from the start?","TWN":"在契約上簽名？原來你打從一開始就是想叫我簽名嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"흐음… 여기 사인하면 평생 당신을 위해 봉사해야 하는 거군요.","JPN":"ふーん……ここにサインすると、一生あなたのために奉仕しないといけないんですよね？","ENG":" Hmm... If I sign this, that means I'm stuck with you for life, huh?","TWN":"嗯嗯…簽下去之後，我就要一輩子為你效勞的意思對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":" …….","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"사인할게요. 이런 계약이 있다면 당신도 제게서 함부로 도망치지 못할 테니까.","JPN":"サインします。こんな契約があったら、あなたも私からは逃げられないでしょうし。","ENG":" I'll sign it. With this contract, you won't be able to run away from me so easily either.","TWN":"我簽。反正只要有份契約，你也無法輕易從我身邊逃走。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"수녀를 부려먹겠다는 그 못된 마음을 교화시킬 좋은 기회라고 생각해요.","JPN":"シスターをこき使おうとするその悪い心を教化するいいチャンスだと思いますよ。","ENG":" Oh, this is a perfect chance to fix your bad habit of bossing nuns around.","TWN":"你竟然想使喚修女，我就趁這個機會好好教育你吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그리고…","JPN":"それに……","ENG":" And...","TWN":"而且……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"당신이라면 분명 좋은 사람이 될 수 있다고 믿으니까요.","JPN":"あなたなら十分いい人になれますから。","ENG":" Because I know you have it in you to be a good person.","TWN":"我相信，你一定能夠成為一個好人的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};